  1	import * as React from 'react';
  2	import { GetPublicAccessBlockCommandOutput } from '@aws-sdk/client-s3';
  3	import { TFunction } from 'react-i18next';
  4	import {
  5	  TreeViewDataItem,
  6	  TextContent,
  7	  TextVariants,
  8	  Text,
  9	  Label,
 10	} from '@patternfly/react-core';
 11	import { BanIcon, ExclamationTriangleIcon } from '@patternfly/react-icons';
 12	
 13	export const SupportedConfig = {
 14	  BlockPublicPolicy: 'BlockPublicPolicy',
 15	  RestrictPublicBuckets: 'RestrictPublicBuckets',
 16	};
 17	
 18	export const areAllChildrenChecked = (checkedItems: Set<string>) =>
 19	  Object.values(SupportedConfig).every((child) => checkedItems.has(child));
 20	
 21	export const areSomeChildrenChecked = (checkedItems: Set<string>) =>
 22	  Object.values(SupportedConfig).some((child) => checkedItems.has(child));
 23	
 24	export const isNoChildChecked = (checkedItems: Set<string>) =>
 25	  Object.values(SupportedConfig).every((child) => !checkedItems.has(child));
 26	
 27	export const getConfigText = (t: TFunction) => ({
 28	  [SupportedConfig.BlockPublicPolicy]: t(
 29	    'Block public access to buckets and objects granted through new public bucket policies'
 30	  ),
 31	  [SupportedConfig.RestrictPublicBuckets]: t(
 32	    'Block public and cross-account access to buckets and objects through any public bucket policies'
 33	  ),
 34	});
 35	
 36	export const showModal = (
 37	  pabData: GetPublicAccessBlockCommandOutput,
 38	  checkedItems: Set<string>,
 39	  t: TFunction
 40	) => {
 41	  const configText = getConfigText(t);
 42	  const disabledConfig = [];
 43	
 44	  Object.entries(SupportedConfig).forEach(([key, value]) => {
 45	    if (
 46	      pabData?.PublicAccessBlockConfiguration?.[key] === true &&
 47	      !checkedItems.has(value)
 48	    )
 49	      disabledConfig.push(configText[value]);
 50	  });
 51	
 52	  return [disabledConfig.length > 0, disabledConfig];
 53	};
 54	
