 56	  let color;
 57	  let text;
 58	  let icon;
 59	  const variant = manage ? 'outline' : 'filled';
 60	  if (areAllChildrenChecked(checkedItems)) {
 61	    color = 'green';
 62	    text = t('Blocked all');
 63	    icon = <BanIcon />;
 64	  } else if (areSomeChildrenChecked(checkedItems)) {
 65	    color = 'gold';
 66	    text = t('Partially blocked');
 67	    icon = <ExclamationTriangleIcon />;
 68	  } else {
 69	    color = 'red';
 70	    text = t('Unblocked all');
 71	    icon = <ExclamationTriangleIcon />;
 72	  }
 73	
 74	  return (
 75	    <Label color={color} icon={icon} variant={variant}>
 76	      {text}
 77	    </Label>
 78	  );
 79	};
