 81	const getChildLabel = (
 82	  manage: boolean,
 83	  checkedItems: Set<string>,
 84	  id: string,
 85	  t: TFunction
 86	) => {
 87	  let color;
 88	  let text;
 89	  let icon;
 90	  const variant = manage ? 'outline' : 'filled';
 91	  if (checkedItems.has(id)) {
 92	    color = 'green';
 93	    text = t('Blocked');
 94	    icon = <BanIcon />;
 95	  } else {
 96	    color = 'red';
 97	    text = t('Unblocked');
 98	    icon = <ExclamationTriangleIcon />;
 99	  }
100	
101	  return (
102	    <Label color={color} icon={icon} variant={variant}>
103	      {text}
104	    </Label>
105	  );
106	};
107	
108	export const getOptions = (
109	  manage: boolean,
110	  checkedItems: Set<string>,
111	  t: TFunction
112	): TreeViewDataItem[] => {
113	  const configText = getConfigText(t);
114	  return [
115	    {
116	      name: (
117	        <TextContent>
118	          <Text component={TextVariants.p}>
119	            {t('Block all public access')} {getLabel(manage, checkedItems, t)}
120	          </Text>
121	          <Text component={TextVariants.small}>
122	            {t(
123	              'Prevent all forms of public access to this bucket and its objects.'
124	            )}{' '}
125	            <br />
126	            {t(
127	              'Overrides all policies and permissions that grant public access. When enabled, it ensures the bucket and all stored data are private and accessible only through explicitly granted permissions.'
128	            )}
129	          </Text>
130	        </TextContent>
131	      ),
132	      id: 'PublicAccessBlockConfiguration',
133	      checkProps: { checked: false, disabled: !manage },
134	      children: [
135	        {
136	          name: (
137	            <TextContent>
138	              <Text component={TextVariants.p}>
139	                {configText[SupportedConfig.BlockPublicPolicy]}{' '}
140	                {getChildLabel(
141	                  manage,
142	                  checkedItems,
143	                  SupportedConfig.BlockPublicPolicy,
144	                  t
145	                )}
146	              </Text>
147	              <Text component={TextVariants.small}>
148	                {t('Prevent new policies from making your data public.')} <br />
149	                {t(
150	                  'Blocks any newly created bucket policy that grants public access to your data, helping prevent accidental exposure in the future.'
151	                )}
152	              </Text>
153	            </TextContent>
154	          ),
155	          id: SupportedConfig.BlockPublicPolicy,
156	          checkProps: { checked: false, disabled: !manage },
157	        },
158	        {
159	          name: (
160	            <TextContent>
161	              <Text component={TextVariants.p}>
162	                {configText[SupportedConfig.RestrictPublicBuckets]}{' '}
163	                {getChildLabel(
164	                  manage,
165	                  checkedItems,
166	                  SupportedConfig.RestrictPublicBuckets,
167	                  t
168	                )}
169	              </Text>
170	              <Text component={TextVariants.small}>
171	                {t(
172	                  'Block all public and cross-account access granted by existing policies.'
173	                )}{' '}
174	                <br />
175	                {t(
176	                  'Restrict access from other accounts or the public internet, even if existing policies currently allow it. This is recommended for keeping your data isolated and secure.'
177	                )}
178	              </Text>
179	            </TextContent>
180	          ),
181	          id: SupportedConfig.RestrictPublicBuckets,
182	          checkProps: { checked: false, disabled: !manage },
183	        },
184	      ],
185	      defaultExpanded: true,
186	    },
187	  ];
188	};

